mapper.select:
select id, code, name, type_category_id as typeCategoryId, login_url as loginUrl, status, create_time, update_time from realm
and `name` like concat('%', #{realmPageRequest.name}, '%')
and `code` = #{realmPageRequest.code}
and `status` = #{realmPageRequest.status}
and type_category_id = #{realmPageRequest.typeCategoryId}
order by update_time desc, create_time desc
